var lines = value.split('\n');
var targetIP = '{#ARPIP}';

for (var i = 0; i < lines.length; i++) {
    if (lines[i].indexOf(targetIP) > -1) {
        var macMatch = lines[i].match(/([A-F0-9]{2}:[A-F0-9]{2}:[A-F0-9]{2}:[A-F0-9]{2}:[A-F0-9]{2}:[A-F0-9]{2})/i);
        if (macMatch) {
            return macMatch[1];
        }
    }
}
return 'not found';

var lines = value.split('\n');
var result = { "data": [] };
var found = false;

for (var i = 0; i < lines.length; i++) {
    // Skip header lines and empty lines
    if (lines[i].match(/^\s*[0-9]+\s+DC/) || lines[i].match(/^\s*[0-9]+\s+D/)) {
        var parts = lines[i].trim().split(/\s+/);
        // parts format: [number, flags, ip, mac, interface]
        if (parts.length >= 5) {
            result.data.push({
                "{#ARPIP}": parts[2],
                "{#ARPMAC}": parts[3],
                "{#ARPIF}": parts[4]
            });
            found = true;
        }
    }
}

// If no entries found with DC format, try simpler pattern
if (!found) {
    for (var i = 0; i < lines.length; i++) {
        var ipMatch = lines[i].match(/([0-9]+\.[0-9]+\.[0-9]+\.[0-9]+)/);
        var macMatch = lines[i].match(/([A-F0-9]{2}:[A-F0-9]{2}:[A-F0-9]{2}:[A-F0-9]{2}:[A-F0-9]{2}:[A-F0-9]{2})/i);
        var intMatch = lines[i].match(/(ether[0-9]+|bridge|vlan)/);

        if (ipMatch && macMatch) {
            result.data.push({
                "{#ARPIP}": ipMatch[1],
                "{#ARPMAC}": macMatch[1],
                "{#ARPIF}": intMatch ? intMatch[1] : "unknown"
            });
        }
    }
}

return JSON.stringify(result);
